export type AnswerOption = {
  label: string
  text: string
}

export type Question = {
  id: string
  text: string
  options: [AnswerOption, AnswerOption, AnswerOption, AnswerOption]
  correctAnswer: string
}

export type Quiz = {
  id: string
  title: string
  questions: Question[]
  createdAt: string
}

export type QuizAttempt = {
  quizId: string
  answers: Record<string, string>
  currentIndex: number
}

export type QuestionResult = {
  questionText: string
  selectedAnswer: string
  correctAnswer: string
  correct: boolean
}

export type ScoreResult = {
  quizTitle: string
  totalQuestions: number
  correctCount: number
  results: QuestionResult[]
}

import type { Quiz } from './types'

const DATA_DIR = import.meta.dir + '/data'
const QUIZZES_FILE = `${DATA_DIR}/quizzes.json`

const readQuizzes = async (): Promise<Quiz[]> => {
  const file = Bun.file(QUIZZES_FILE)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return text.trim() ? JSON.parse(text) : []
}

const writeQuizzes = async (quizzes: Quiz[]): Promise<void> => {
  await Bun.write(QUIZZES_FILE, JSON.stringify(quizzes, null, 2))
}

export const getAllQuizzes = async (): Promise<Quiz[]> => {
  return readQuizzes()
}

export const getQuizById = async (id: string): Promise<Quiz | undefined> => {
  const quizzes = await readQuizzes()
  return quizzes.find((q) => q.id === id)
}

export const saveQuiz = async (quiz: Quiz): Promise<void> => {
  const quizzes = await readQuizzes()
  const existingIndex = quizzes.findIndex((q) => q.id === quiz.id)
  if (existingIndex >= 0) {
    quizzes[existingIndex] = quiz
  } else {
    quizzes.push(quiz)
  }
  await writeQuizzes(quizzes)
}

export const deleteQuiz = async (id: string): Promise<void> => {
  const quizzes = await readQuizzes()
  const filtered = quizzes.filter((q) => q.id !== id)
  await writeQuizzes(filtered)
}

