    h('h1', { style: styles.heading }, 'Quiz Builder'),
    h('div', { style: styles.flex },
      h('a', { href: '/create' },
        h('button', { style: styles.button, 'p-trigger': 'click:navigate' }, '+ Create New Quiz'),
      ),
    ),
    h('div', { style: { marginTop: '20px' } },
      quizzes.length === 0
        ? h('p', { style: { color: '#6b7280' } }, 'No quizzes yet. Create your first one!')
        : h(Fragment, {},
            ...quizzes.map((quiz) =>
              h('div', { style: styles.card },
                h('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
                  h('div', {},
                    h('h3', { style: { margin: '0 0 4px 0', fontSize: '16px' } }, quiz.title),
                    h('span', { style: { fontSize: '13px', color: '#6b7280' } },
                      `${quiz.questions.length} question${quiz.questions.length !== 1 ? 's' : ''}`
                    ),
                  ),
                  h('div', { style: styles.flex },
                    h('a', { href: `/take/${quiz.id}` },
                      h('button', { style: styles.button, 'p-trigger': 'click:startQuiz' }, 'Take Quiz'),
                    ),
                    h('a', { href: `/delete/${quiz.id}` },
                      h('button', { style: styles.buttonDanger, 'p-trigger': 'click:deleteQuiz' }, 'Delete'),
                    ),
                  ),
                ),
              )
            ),
          ),
    ),
  )
  return template as unknown as string
}

export const renderCreateQuiz = (questionCount: number = 1): string => {
