      h('h3', { style: styles.subheading }, `Question ${i + 1}`),
      h('label', { style: styles.label }, 'Question Text'),
      h('input', {
        style: styles.input,
        type: 'text',
        name: `question_${i}_text`,
        placeholder: 'Enter your question...',
        required: 'true',
      }),
      ...labels.map((label) =>
        h('div', { style: styles.optionRow },
          h('span', { style: styles.optionLabel }, `${label}.`),
          h('input', {
            style: { ...styles.input, marginBottom: '0' },
            type: 'text',
            name: `question_${i}_option_${label}`,
            placeholder: `Option ${label}`,
            required: 'true',
          }),
        )
      ),
      h('div', { style: { marginTop: '8px' } },
        h('label', { style: styles.label }, 'Correct Answer'),
        h('select', {
          style: { ...styles.input, width: 'auto' },
          name: `question_${i}_correct`,
        },
          ...labels.map((label) =>
            h('option', { value: label }, `Option ${label}`)
          ),
        ),
      ),
    )
  })

  const template = h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Create a Quiz'),
    h('form', { method: 'POST', action: '/create' },
      h('label', { style: styles.label }, 'Quiz Title'),
      h('input', {
        style: styles.input,
        type: 'text',
        name: 'title',
        placeholder: 'Enter quiz title...',
        required: 'true',
      }),
      h('input', { type: 'hidden', name: 'questionCount', value: String(questionCount) }),
      ...questionFields,
      h('div', { style: styles.flex },
        h('a', { href: `/create?questions=${questionCount + 1}` },
          h('button', { type: 'button', style: styles.buttonSecondary, 'p-trigger': 'click:addQuestion' }, '+ Add Question'),
        ),
        h('button', { type: 'submit', style: styles.button }, 'Save Quiz'),
        h('a', { href: '/' },
          h('button', { type: 'button', style: styles.buttonSecondary }, 'Cancel'),
        ),
      ),
    ),
  )
  return template as unknown as string
}

export const renderTakeQuestion = (quiz: Quiz, attempt: QuizAttempt): string => {
  const question = quiz.questions[attempt.currentIndex]
  const selectedAnswer = attempt.answers[question.id] ?? ''
  const isLast = attempt.currentIndex === quiz.questions.length - 1

  const template = h('div', { style: styles.container },
    h('h1', { style: styles.heading }, quiz.title),
    h('p', { style: styles.progressText },
      `Question ${attempt.currentIndex + 1} of ${quiz.questions.length}`
    ),
    h('div', { style: styles.card },
      h('h2', { style: { ...styles.subheading, marginBottom: '16px' } }, question.text),
      h('form', { method: 'POST', action: `/take/${quiz.id}` },
        h('input', { type: 'hidden', name: 'questionIndex', value: String(attempt.currentIndex) }),
        h('input', { type: 'hidden', name: 'questionId', value: question.id }),
        ...question.options.map((option) => {
          const isSelected = selectedAnswer === option.label
          return h('label', { style: isSelected ? styles.radioLabelSelected : styles.radioLabel },
            h('input', {
              type: 'radio',
              name: 'answer',
              value: option.label,
              ...(isSelected ? { checked: 'true' } : {}),
            }),
            h('span', { style: styles.optionLabel }, `${option.label}.`),
            h('span', {}, option.text),
          )
        }),
        h('div', { style: { ...styles.flex, marginTop: '16px' } },
          h('button', { type: 'submit', style: styles.button },
            isLast ? 'Finish Quiz' : 'Next'
          ),
        ),
      ),
    ),
  )
  return template as unknown as string
}

export const renderScore = (score: ScoreResult): string => {
  const percentage = score.totalQuestions > 0
    ? Math.round((score.correctCount / score.totalQuestions) * 100)
    : 0

  const template = h('div', { style: styles.container },
    h('h1', { style: styles.heading }, 'Quiz Results'),
    h('h2', { style: { ...styles.subheading, marginBottom: '20px' } }, score.quizTitle),
    h('div', { style: styles.scoreBox },
      h('div', { style: styles.scoreBig }, `${percentage}%`),
      h('p', { style: { fontSize: '16px', color: '#374151', marginTop: '8px' } },
        `${score.correctCount} out of ${score.totalQuestions} correct`
      ),
    ),
    h('h3', { style: styles.subheading }, 'Question Breakdown'),
    ...score.results.map((result, i) => {
      const correctOption = result.correctAnswer
      const selectedOption = result.selectedAnswer || 'No answer'
      return h('div', { style: styles.questionBlock },
        h('p', { style: { fontWeight: '600', marginBottom: '4px' } },
          `${i + 1}. ${result.questionText}`
        ),
        h('p', { style: result.correct ? styles.correct : styles.incorrect },
          result.correct
            ? `Correct (${correctOption})`
            : `Incorrect — You chose ${selectedOption}, correct was ${correctOption}`
        ),
      )
    }),
    h('div', { style: { ...styles.flex, marginTop: '20px' } },
      h('a', { href: '/' },
        h('button', { style: styles.button }, 'Back to Quizzes'),
      ),
    ),
  )
  return template as unknown as string
}

import { getAllQuizzes, getQuizById, saveQuiz, deleteQuiz } from './store'
import { renderQuizList, renderCreateQuiz, renderTakeQuestion, renderScore } from './render'
import type { Quiz, Question, QuizAttempt, ScoreResult, QuestionResult } from './types'

const generateId = (): string => crypto.randomUUID()

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const formData = await req.formData()
  const entries: Record<string, string> = {}
  formData.forEach((value, key) => {
    entries[key] = String(value)
  })
  return entries
}

const wrapHtml = (title: string, body: string): Response => {
  const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${title} — Quiz Builder</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8fafc; color: #1e293b; line-height: 1.6; }
    a { text-decoration: none; }
  </style>
</head>
<body>${body}</body>
</html>`
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const activeAttempts = new Map<string, QuizAttempt>()

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // Home — list quizzes
  if (path === '/' && method === 'GET') {
    const quizzes = await getAllQuizzes()
    const body = renderQuizList(quizzes)
    return wrapHtml('Home', body)
  }

  // Create quiz form
  if (path === '/create' && method === 'GET') {
    const questionCount = parseInt(url.searchParams.get('questions') ?? '1', 10)
    const count = Math.max(1, Math.min(questionCount, 50))
    const body = renderCreateQuiz(count)
    return wrapHtml('Create Quiz', body)
  }

  // Save new quiz
  if (path === '/create' && method === 'POST') {
    const data = await parseFormData(req)
    const title = data.title?.trim()
    if (!title) {
      return wrapHtml('Error', '<div style="padding:24px"><p>Quiz title is required.</p><a href="/create">Go back</a></div>')
    }

    const questionCount = parseInt(data.questionCount ?? '1', 10)
    const questions: Question[] = []

    for (let i = 0; i < questionCount; i++) {
      const text = data[`question_${i}_text`]?.trim()
      if (!text) continue

      const labels = ['A', 'B', 'C', 'D'] as const
      const options = labels.map((label) => ({
        label,
        text: data[`question_${i}_option_${label}`]?.trim() || `Option ${label}`,
      })) as Question['options']

      const correctAnswer = data[`question_${i}_correct`] || 'A'

      questions.push({
        id: generateId(),
        text,
        options,
        correctAnswer,
      })
    }

    if (questions.length === 0) {
      return wrapHtml('Error', '<div style="padding:24px"><p>At least one question is required.</p><a href="/create">Go back</a></div>')
    }

    const quiz: Quiz = {
      id: generateId(),
      title,
      questions,
      createdAt: new Date().toISOString(),
    }

    await saveQuiz(quiz)
    return Response.redirect(new URL('/', req.url).toString(), 303)
  }

  // Delete quiz
  const deleteMatch = path.match(/^\/delete\/(.+)$/)
  if (deleteMatch && method === 'GET') {
    const quizId = deleteMatch[1]
    await deleteQuiz(quizId)
    activeAttempts.delete(quizId)
    return Response.redirect(new URL('/', req.url).toString(), 303)
  }

  // Start / continue taking a quiz (GET)
  const takeGetMatch = path.match(/^\/take\/(.+)$/)
  if (takeGetMatch && method === 'GET') {
    const quizId = takeGetMatch[1]
    const quiz = await getQuizById(quizId)
    if (!quiz) {
      return wrapHtml('Not Found', '<div style="padding:24px"><p>Quiz not found.</p><a href="/">Go home</a></div>')
    }

    if (!activeAttempts.has(quizId)) {
      activeAttempts.set(quizId, {
        quizId,
        answers: {},
        currentIndex: 0,
      })
    }

    const attempt = activeAttempts.get(quizId)!
    const body = renderTakeQuestion(quiz, attempt)
    return wrapHtml(`Take: ${quiz.title}`, body)
  }

  // Submit answer for a question (POST)
  const takePostMatch = path.match(/^\/take\/(.+)$/)
  if (takePostMatch && method === 'POST') {
    const quizId = takePostMatch[1]
    const quiz = await getQuizById(quizId)
    if (!quiz) {
      return wrapHtml('Not Found', '<div style="padding:24px"><p>Quiz not found.</p><a href="/">Go home</a></div>')
    }

    const data = await parseFormData(req)
    const questionId = data.questionId
    const answer = data.answer
    const questionIndex = parseInt(data.questionIndex ?? '0', 10)

    const attempt = activeAttempts.get(quizId) ?? {
      quizId,
      answers: {},
      currentIndex: 0,
    }

    if (questionId && answer) {
      attempt.answers[questionId] = answer
    }

    const nextIndex = questionIndex + 1

    // If there are more questions, advance
    if (nextIndex < quiz.questions.length) {
      attempt.currentIndex = nextIndex
      activeAttempts.set(quizId, attempt)
      const body = renderTakeQuestion(quiz, attempt)
      return wrapHtml(`Take: ${quiz.title}`, body)
    }

    // All questions answered — compute score
    const results: QuestionResult[] = quiz.questions.map((q) => {
      const selected = attempt.answers[q.id] ?? ''
      return {
        questionText: q.text,
        selectedAnswer: selected,
        correctAnswer: q.correctAnswer,
        correct: selected === q.correctAnswer,
      }
    })

    const score: ScoreResult = {
      quizTitle: quiz.title,
      totalQuestions: quiz.questions.length,
      correctCount: results.filter((r) => r.correct).length,
      results,
    }

    // Clean up attempt
    activeAttempts.delete(quizId)

    const body = renderScore(score)
    return wrapHtml('Results', body)
  }

  return wrapHtml('Not Found', '<div style="padding:24px"><p>Page not found.</p><a href="/">Go home</a></div>')
}

const server = Bun.serve({
  port: parseInt(process.env.PORT ?? '3000', 10),
  fetch: handleRequest,
})

console.log(`Quiz Builder running at http://localhost:${server.port}`)

export { handleRequest }
